CREATE TABLE IF NOT EXISTS admins (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, email VARCHAR(190) NOT NULL UNIQUE, password VARCHAR(255) NOT NULL, active TINYINT(1) NOT NULL DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS settings (`key` VARCHAR(100) PRIMARY KEY, value TEXT NULL);
CREATE TABLE IF NOT EXISTS products (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, slug VARCHAR(190) NOT NULL UNIQUE, name VARCHAR(190) NOT NULL, type ENUM('file_link','account_stock','manual') NOT NULL DEFAULT 'file_link', description TEXT NOT NULL, price BIGINT UNSIGNED NOT NULL, delivery_url TEXT NULL, active TINYINT(1) NOT NULL DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS product_fields (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, product_id INT UNSIGNED NOT NULL, label VARCHAR(150) NOT NULL, type ENUM('text','email','tel','textarea') NOT NULL DEFAULT 'text', required TINYINT(1) NOT NULL DEFAULT 0, sort_order SMALLINT UNSIGNED NOT NULL DEFAULT 0, FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS orders (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, invoice VARCHAR(50) NOT NULL UNIQUE, access_token VARCHAR(100) NOT NULL UNIQUE, buyer_name VARCHAR(190) NOT NULL, buyer_email VARCHAR(190) NOT NULL, total BIGINT UNSIGNED NOT NULL, status ENUM('pending','paid','expired','cancelled','fulfilled') NOT NULL DEFAULT 'pending', paid_at DATETIME NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS order_items (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, order_id BIGINT UNSIGNED NOT NULL, product_id INT UNSIGNED NOT NULL, product_name VARCHAR(190) NOT NULL, product_type VARCHAR(30) NOT NULL, price BIGINT UNSIGNED NOT NULL, delivery_url TEXT NULL, stock_item_id BIGINT UNSIGNED NULL, delivered_at DATETIME NULL, FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS order_field_values (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, order_id BIGINT UNSIGNED NOT NULL, field_id INT UNSIGNED NOT NULL, value TEXT NULL, FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS stock_items (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, product_id INT UNSIGNED NOT NULL, payload MEDIUMTEXT NOT NULL, status ENUM('available','sold','disabled') NOT NULL DEFAULT 'available', order_item_id BIGINT UNSIGNED NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, sold_at DATETIME NULL, INDEX(product_id,status), FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS payments (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, order_id BIGINT UNSIGNED NOT NULL UNIQUE, gateway VARCHAR(30) NOT NULL DEFAULT 'pakasir', status VARCHAR(30) NOT NULL DEFAULT 'pending', payment_method VARCHAR(50) NULL, raw_response JSON NULL, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS deliveries (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, order_item_id BIGINT UNSIGNED NOT NULL, type VARCHAR(30) NOT NULL, download_token VARCHAR(100) NULL UNIQUE, sent_at DATETIME NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(order_item_id) REFERENCES order_items(id) ON DELETE CASCADE);
